import json, machine, vfs, os, time as t
import seedsigner_lvgl_screens as ss
ss.init(); ss.set_screensaver_timeout(0)
try: os.listdir('/sd')
except OSError: vfs.mount(vfs.VfsFat(machine.SDCard(slot=0, width=4)), '/sd')
loc='zh_Hans_CN'
p={f: open('/sd/'+loc+'/'+f,'rb').read() for f in json.loads(ss.locale_pack_files(loc))}
print('load', loc, ss.load_locale(loc, p))

def m(): return ss.mem_stats()
def show(tag):
    s=m()
    print('%-26s used=%2d%% max=%-6d frag=%2d%% big=%-7d' % (
        tag, s['lvgl_used_pct'], s['lvgl_max_used'], s['lvgl_frag_pct'], s['lvgl_free_biggest']))

def blist(title, labels):
    ss.clear_result_queue()
    ss.button_list_screen({'top_nav': {'title': (title or ' ')[:14],
        'show_back_button': True, 'show_power_button': False}, 'button_list': labels}); t.sleep_ms(50)

def status(title, body):
    ss.clear_result_queue()
    ss.large_icon_status_screen({'top_nav': {'title': (title or ' ')[:14],
        'show_back_button': False, 'show_power_button': False},
        'status_type': 'warning', 'status_headline': (title or ' ')[:14], 'text': body,
        'button_list': ['OK'], 'is_bottom_list': True, 'warning_edges': False}); t.sleep_ms(50)

class Stop(Exception): pass
USED_MAX=78; BIG_MIN=22000; n=[0]
def guard(tag):
    s=m(); n[0]+=1
    print('%-26s used=%2d%% max=%-6d frag=%2d%% big=%-7d' % (
        tag, s['lvgl_used_pct'], s['lvgl_max_used'], s['lvgl_frag_pct'], s['lvgl_free_biggest']))
    if s['lvgl_used_pct']>=USED_MAX or s['lvgl_free_biggest']<BIG_MIN:
        print('>>> STOP before overflow at %s (screen #%d): used=%d%% big=%d' % (
            tag, n[0], s['lvgl_used_pct'], s['lvgl_free_biggest']))
        raise Stop()

show('baseline')
try:
    for name, labels, bodies in GROUPS:
        # real CJK title for this screen family (first label / body), per-codepoint slice
        gtitle = (labels[0] if labels else (bodies[0] if bodies else name))
        for i in range(0, len(labels), 8):
            blist(gtitle, labels[i:i+8]); guard('%s L%d' % (name, i))
        for bi, body in enumerate(bodies):
            for j in range(0, len(body), 80):
                status(gtitle, body[j:j+80]); guard('%s B%d.%d' % (name, bi, j))
except Stop:
    pass
show('LAST-SAFE')
print('--- done (screens rendered: %d) ---' % n[0])
